import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { Product } from '../types';
import { api } from '../services/api';
import { useCart } from '../context/CartContext';

const ProductDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { addToCart } = useCart();

  const [product, setProduct] = useState<Product | null>(null);
  const [loading, setLoading] = useState(true);
  const [quantity, setQuantity] = useState(1);
  const [error, setError] = useState<string | null>(null);
  const [addedToCart, setAddedToCart] = useState(false);

  useEffect(() => {
    const fetchProduct = async () => {
      if (!id) return;

      try {
        setLoading(true);
        setError(null);
        const data = await api.get<Product>(`/products/${id}`);
        setProduct(data);
      } catch (err) {
        setError('无法加载产品信息，请稍后重试');
      } finally {
        setLoading(false);
      }
    };

    fetchProduct();
  }, [id]);

  const handleQuantityChange = (value: string) => {
    const num = parseInt(value, 10);
    if (num > 0 && product && num <= product.stock) {
      setQuantity(num);
    } else if (num > product.stock) {
      setQuantity(product.stock);
    }
  };

  const handleAddToCart = () => {
    if (product) {
      addToCart({ ...product, quantity });
      setAddedToCart(true);
      setTimeout(() => setAddedToCart(false), 2000);
    }
  };

  const goBack = () => {
    navigate('/products');
  };

  if (loading) {
    return (
      <div className="product-detail-container">
        <div className="loading">加载中...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="product-detail-container">
        <div className="error-message">{error}</div>
        <button onClick={goBack} className="back-btn">返回商品列表</button>
      </div>
    );
  }

  if (!product) {
    return (
      <div className="product-detail-container">
        <div className="not-found">产品不存在</div>
        <button onClick={goBack} className="back-btn">返回商品列表</button>
      </div>
    );
  }

  return (
    <div className="product-detail-container">
      <button onClick={goBack} className="back-btn">
        ← 返回商品列表
      </button>

      <div className="product-detail">
        <div className="product-image-container">
          <img
            src={product.image || 'https://via.placeholder.com/400x400?text=No+Image'}
            alt={product.name}
            className="product-image"
          />
        </div>

        <div className="product-info">
          <h1 className="product-name">{product.name}</h1>

          <div className="product-category">
            <span className="category-label">分类:</span>
            <span className="category-value">{product.category || '未分类'}</span>
          </div>

          <div className="product-price">
            <span className="price-symbol">¥</span>
            <span className="price-value">{product.price.toFixed(2)}</span>
          </div>

          <div className="product-stock">
            <span className={product.stock > 0 ? 'in-stock' : 'out-of-stock'}>
              {product.stock > 0 ? `库存: ${product.stock} 件` : '缺货'}
            </span>
          </div>

          <div className="product-description">
            <h3>商品描述</h3>
            <p>{product.description || '暂无描述'}</p>
          </div>

          <div className="product-actions">
            <div className="quantity-selector">
              <label htmlFor="quantity">数量:</label>
              <input
                id="quantity"
                type="number"
                min="1"
                max={product.stock}
                value={quantity}
                onChange={(e) => handleQuantityChange(e.target.value)}
                disabled={product.stock === 0}
              />
            </div>

            <button
              onClick={handleAddToCart}
              className={`add-to-cart-btn ${addedToCart ? 'success' : ''}`}
              disabled={product.stock === 0}
            >
              {addedToCart ? '✓ 已加入购物车' : '加入购物车'}
            </button>
          </div>

          <div className="product-meta">
            <span>上架时间: {product.createdAt ? new Date(product.createdAt).toLocaleDateString() : '未知'}</span>
          </div>
        </div>
