        }

        input:focus {
          outline: none;
          border-color: #667eea;
          box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
        }

        input:disabled {
          background: #f5f5f5;
          cursor: not-allowed;
        }

        input.input-error {
          border-color: #c00;
        }

        .field-error {
          color: #c00;
          font-size: 12px;
        }

        .submit-btn {
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          color: white;
