```typescript
import { Router, Request, Response } from 'express';
import { Pool } from 'pg';
import { Order, OrderItem } from '../../src/types/index';

const router = Router();

interface AuthRequest extends Request {
  userId?: number;
}

interface OrderRow {
  id: number;
  user_id: number;
  total: number;
  status: 'pending' | 'processing' | 'shipped' | 'delivered' | 'cancelled';
  created_at: string;
}

interface OrderItemRow {
  id: number;
  order_id: number;
  product_id: number;
  quantity: number;
  price: number;
  product_name?: string;
  product_image?: string;
}

export default (pool: Pool) => {
  // Get all orders for the current user
  router.get('/', async (req: AuthRequest, res: Response) => {
    try {
      const userId = req.userId;

      if (!userId) {
        return res.status(401).json({ error: 'Unauthorized' });
      }

      const ordersResult = await pool.query<OrderRow>(
        'SELECT id, user_id, total, status, created_at FROM orders WHERE user_id = $1 ORDER BY created_at DESC',
        [userId]
      );

      const orders: Order[] = [];

      for (const row of ordersResult.rows) {
        const itemsResult = await pool.query<OrderItemRow>(
          `SELECT oi.id, oi.order_id, oi.product_id, oi.quantity, oi.price,
                  p.name as product_name, p.image as product_image
           FROM order_items oi
           JOIN products p ON oi.product_id = p.id
           WHERE oi.order_id = $1`,
          [row.id]
        );

        const items: OrderItem[] = itemsResult.rows.map((item) => ({
          productId: item.product_id,
          quantity: item.quantity,
          price: item.price,
          product: item.product_name
            ? {
                id: item.product_id,
                name: item.product_name,
                description: '',
                price: item.price,
                stock: 0,
                image: item.product_image || '',
                category: '',
                createdAt: '',
              }
            : undefined,
        }));

        orders.push({
          id: row.id,
          userId: row.user_id,
          items,
          total: row.total,
          status: row.status,
          createdAt: row.created_at,
        });
      }

      return res.json(orders);
    } catch (error) {
      console.error('Error fetching orders:', error);
      return res.status(500).json({ error: 'Internal server error' });
    }
  });

  // Get a specific order by ID
  router.get('/:id', async (req: AuthRequest, res: Response) => {
    try {
      const userId = req.userId;
      const orderId = parseInt(req.params.id, 10);

      if (!userId) {
        return res.status(401).json({ error: 'Unauthorized' });
      }

      if (isNaN(orderId)) {
        return res.status(400).json({ error: 'Invalid order ID' });
      }

      const orderResult = await pool.query<OrderRow>(
        'SELECT id, user_id, total, status, created_at FROM orders WHERE id = $1 AND user_id = $2',
        [orderId, userId]
      );

      if (orderResult.rows.length === 0) {
        return res.status(404).json({ error: 'Order not found' });
      }

      const orderRow = orderResult.rows[0];

      const itemsResult = await pool.query<OrderItemRow>(
        `SELECT oi.id, oi.order_id, oi.product_id, oi.quantity, oi.price,
                p.name as product_name, p.image as product_image
         FROM order_items oi
         JOIN products p ON oi.product_id = p.id
         WHERE oi.order_id = $1`,
        [orderId]
      );

      const items: OrderItem[] = itemsResult.rows.map((item) => ({
        productId: item.product_id,
        quantity: item.quantity,
        price: item.price,
        product: item.product_name
          ? {
              id: item.product_id,
              name: item.product_name,
              description: '',
              price: item.price,
              stock: 0,
              image: item.product_image || '',
              category: '',
              createdAt: '',
            }
          : undefined,
      }));

      const order: Order = {
        id: orderRow.id,
        userId: orderRow.user_id,
        items,
        total: orderRow.total,
        status: orderRow.status,
        createdAt: orderRow.created_at,
      };

      return res.json(order);
    } catch (error) {
      console.error('Error fetching order:', error);
      return res.status(500).json({ error: 'Internal server error' });
    }
  });

  // Create a new order
  router.post('/', async (req: AuthRequest, res: Response) => {
    const client = await pool.connect();
    try {
      const userId = req.userId;
      const { items } = req.body;

      if (!userId) {
        return res.status(401).json({ error: 'Unauthorized' });
      }

      if (!items || !Array.isArray(items) || items.length === 0) {
        return res.status(400).json({ error: 'Invalid order items' });
      }

      await client.query('BEGIN');

      // Verify stock availability and calculate total
      let total = 0;
      const orderItems: Array<{ productId: number; quantity: number; price: number }> = [];

      for (const item of items) {
        const productResult = await client.query(
          'SELECT id, price, stock FROM products WHERE id = $1 FOR UPDATE',
          [item.productId]
        );

        if (productResult.rows.length === 0) {
          await client.query('ROLLBACK');
          return res.status(404).json({ error: `Product ${item.productId} not found` });
        }

        const product = productResult.rows[0];

        if (product.stock < item.quantity) {
          await client.query('ROLLBACK');
          return res
            .status(400)
            .json({ error: `Insufficient stock for product ${item.productId}` });
        }

        total += product.price * item.quantity;
        orderItems.push({
          productId: item.productId,
          quantity: item.quantity,
          price: product.price,
        });

        // Reduce stock
        await client.query('UPDATE products SET stock = stock - $1 WHERE id = $2', [
          item.quantity,
          item.productId,
        ]);
      }

      // Create order
      const orderResult = await client.query<OrderRow>(
        'INSERT INTO orders (user_id, total, status) VALUES ($1, $2, $3) RETURNING id, user_id, total, status, created_at',
        [userId, total, 'pending']
      );

      const orderRow = orderResult.rows[0];

      // Create order items
      for (const item of orderItems) {
        await client.query(
          'INSERT INTO order_items (order_id, product_id, quantity, price) VALUES ($1, $2, $3, $4)',
          [orderRow.id, item.productId, item.quantity, item.price]
        );
      }

      // Clear user's cart
      await client.query('DELETE FROM cart WHERE user_id = $1', [userId]);

      await client.query('COMMIT');

      // Fetch the complete order
      const completeOrder: Order = {
        id: orderRow.id,
        userId: orderRow.user_id,
        items: orderItems.map((item) => ({
          productId: item.productId,
          quantity: item.quantity,
          price: item.price,
        })),
        total: orderRow.total,
        status: orderRow.status,
        createdAt: orderRow.created_at,
      };

      return res.status(201).json(completeOrder);
    } catch (error) {
      await client.query('ROLLBACK');
      console.error('Error creating order:', error);
      return res.status(500).json({ error: 'Internal server error' });
    } finally {
      client.release();
    }
  });

  // Update order status (for admin or specific status transitions)
  router.patch('/:id/status', async (req: AuthRequest, res: Response) => {
    try {
      const userId = req.userId;
      const orderId = parseInt(req.params.id, 10);
      const { status } = req.body;

      if (!userId) {
        return res.status(401).json({ error: 'Unauthorized' });
      }

      if (isNaN(orderId)) {
        return res.status(400).json({ error: 'Invalid order ID' });
      }

      const validStatuses = ['pending', 'processing', 'shipped', 'delivered', 'cancelled'];
      if (!validStatuses.includes(status)) {
        return res.status(400).json({ error: 'Invalid status' });
      }

      const orderResult = await pool.query<OrderRow>(
        'SELECT id, user_id, status FROM orders WHERE id = $1',
        [orderId]
      );

      if (orderResult.rows.length === 0) {
        return res.status(404).json({ error: 'Order not found' });
      }

      const order = orderResult.rows[0];

      // Only allow the order owner or status transitions for non-cancelled orders
      if (order.user_id !== userId && status !== 'cancelled') {
        return res.status(403).json({ error: 'Forbidden' });
      }

      // Cannot update cancelled orders
      if (order.status === 'cancelled') {
        return res.status(400).json({ error: 'Cannot update cancelled order' });
      }

      await pool.query('UPDATE orders SET status = $1 WHERE id = $2', [status, orderId]);

      // If cancelled, restore stock
      if (status === 'cancelled') {
        const itemsResult = await pool.query<OrderItemRow>(
          'SELECT product_id, quantity FROM order_items WHERE order_id = $1',
          [orderId]
        );

        for (const item of itemsResult.rows) {
          await pool.query('UPDATE products SET stock = stock + $1 WHERE id = $2', [
            item.quantity,
            item.product_id,
          ]);
        }
      }

      return res.json({ message: 'Order status updated', orderId, status });
    } catch (error) {
      console.error('Error updating order status:', error);
      return res.status(500).json({ error: 'Internal server error' });
    }
  });

  // Cancel an order
  router.post('/:id/cancel', async (req: AuthRequest, res: Response) => {
    try {
      const userId = req.userId;
      const orderId = parseInt(req.params.id, 10);

      if (!userId) {
        return res.status(401).json({ error: 'Unauthorized' });
      }

      if (isNaN(orderId)) {
        return res.status(400).json({ error: 'Invalid order ID' });
      }

      const orderResult = await pool.query<OrderRow>(
        'SELECT id, user_id, status FROM orders WHERE id = $1 AND user_id = $2',
        [orderId, userId]
      );

      if (orderResult.rows.length === 0) {
        return res.status(404).json({ error: 'Order not found' });
      }

      const order = orderResult.rows[0];

      if (order.status === 'cancelled') {
        return res.status(400).json({ error: 'Order is already cancelled' });
      }

      if (order.status === 'delivered' || order.status === 'shipped') {
        return res.status(400).json({ error: 'Cannot cancel order that has been shipped or delivered' });
      }

      // Cancel the order
      await pool.query('UPDATE orders SET status = $1 WHERE id = $2', ['cancelled', orderId]);

      // Restore stock
      const itemsResult = await pool.query<OrderItemRow>(
        'SELECT product_id, quantity FROM order_items WHERE order_id = $1',
        [orderId]
      );

      for (const item of itemsResult.rows) {
        await pool.query('UPDATE products SET stock = stock + $1 WHERE id = $2', [
          item.quantity,
          item.product_id,
        ]);
      }

      return res.json({ message: 'Order cancelled successfully', orderId });
    } catch (error) {
      console.error('Error cancelling order:', error);
      return res.status(500).json({ error: 'Internal server error' });
    }
  });

  return router;
};
