const express = require('express');
const sqlite3 = require('sqlite3').verbose();
const cors = require('cors');
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');

const app = express();
const PORT = 3001;
const JWT_SECRET = 'ecommerce-secret-key-2024';

app.use(cors());
app.use(express.json());

// Initialize SQLite database
const db = new sqlite3.Database('./ecommerce.db');

// Create tables
db.serialize(() => {
  db.run(`CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    username TEXT UNIQUE NOT NULL,
    email TEXT UNIQUE NOT NULL,
    password TEXT NOT NULL
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS products (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    price REAL NOT NULL,
    stock INTEGER NOT NULL,
    category TEXT,
    description TEXT
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS orders (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    userId INTEGER NOT NULL,
    products TEXT NOT NULL,
    total REAL NOT NULL,
    status TEXT DEFAULT 'pending',
    createdAt TEXT DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (userId) REFERENCES users(id)
  )`);

  db.run(`CREATE TABLE IF NOT EXISTS cart (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    userId INTEGER NOT NULL,
    productId INTEGER NOT NULL,
    quantity INTEGER NOT NULL DEFAULT 1,
    FOREIGN KEY (userId) REFERENCES users(id),
    FOREIGN KEY (productId) REFERENCES products(id)
  )`);
});

// Seed some initial products
db.get("SELECT COUNT(*) as count FROM products", (err, row) => {
  if (row.count === 0) {
    const products = [
      ['iPhone 15 Pro', 999.99, 50, 'Electronics', 'Latest Apple flagship phone'],
      ['MacBook Pro M3', 1999.99, 30, 'Electronics', 'Powerful laptop with M3 chip'],
      ['AirPods Pro', 249.99, 100, 'Electronics', 'Premium wireless earbuds'],
      ['Nike Air Max', 149.99, 75, 'Sports', 'Comfortable running shoes'],
      ['Sony WH-1000XM5', 349.99, 40, 'Electronics', 'Premium noise-canceling headphones'],
      ['Samsung 65" TV', 1299.99, 20, 'Electronics', '4K Smart TV'],
      ['Adidas Jacket', 89.99, 60, 'Sports', 'Lightweight sports jacket'],
      ['Canon EOS R5', 3899.99, 15, 'Electronics', 'Professional mirrorless camera']
    ];
    const stmt = db.prepare("INSERT INTO products (name, price, stock, category, description) VALUES (?, ?, ?, ?, ?)");
    products.forEach(p => stmt.run(p));
    stmt.finalize();
  }
});

// Middleware for authentication
const authenticate = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'No token provided' });

  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    req.userId = decoded.userId;
    next();
  } catch (err) {
    res.status(401).json({ error: 'Invalid token' });
  }
};

// ============ USER ROUTES ============

// Register
app.post('/api/users/register', (req, res) => {
  const { username, email, password } = req.body;
  if (!username || !email || !password) {
    return res.status(400).json({ error: 'All fields are required' });
  }

  const hashedPassword = bcrypt.hashSync(password, 10);

  db.run(
    "INSERT INTO users (username, email, password) VALUES (?, ?, ?)",
    [username, email, hashedPassword],
    function(err) {
      if (err) {
        return res.status(400).json({ error: 'Username or email already exists' });
      }
      const token = jwt.sign({ userId: this.lastID }, JWT_SECRET, { expiresIn: '24h' });
      res.json({ 
        token, 
        user: { id: this.lastID, username, email } 
      });
    }
  );
});

// Login
app.post('/api/users/login', (req, res) => {
  const { email, password } = req.body;

  db.get("SELECT * FROM users WHERE email = ?", [email], (err, user) => {
    if (err || !user) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    if (!bcrypt.compareSync(password, user.password)) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const token = jwt.sign({ userId: user.id }, JWT_SECRET, { expiresIn: '24h' });
    res.json({ 
      token, 
      user: { id: user.id, username: user.username, email: user.email } 
    });
  });
});

// Get user info
app.get('/api/users/me', authenticate, (req, res) => {
  db.get("SELECT id, username, email FROM users WHERE id = ?", [req.userId], (err, user) => {
    if (err || !user) {
      return res.status(404).json({ error: 'User not found' });
    }
    res.json(user);
  });
});

// Update user info
app.put('/api/users/me', authenticate, (req, res) => {
  const { username, email } = req.body;

  db.run(
    "UPDATE users SET username = ?, email = ? WHERE id = ?",
    [username, email, req.userId],
    function(err) {
      if (err) {
        return res.status(400).json({ error: 'Update failed' });
      }
      res.json({ id: req.userId, username, email });
    }
  );
});

// ============ PRODUCT ROUTES ============

// Get all products
app.get('/api/products', (req, res) => {
  const { search, category } = req.query;
  let query = "SELECT * FROM products WHERE 1=1";
  const params = [];

  if (search) {
    query += " AND (name LIKE ? OR description LIKE ?)";
    params.push(`%${search}%`, `%${search}%`);
  }

  if (category) {
    query += " AND category = ?";
    params.push(category);
  }

  db.all(query, params, (err, products) => {
    if (err) {
      return res.status(500).json({ error: 'Failed to fetch products' });
    }
    res.json(products);
  });
});

// Get single product
app.get('/api/products/:id', (req, res) => {
  db.get("SELECT * FROM products WHERE id = ?", [req.params.id], (err, product) => {
    if (err || !product) {
      return res.status(404).json({ error: 'Product not found' });
    }
    res.json(product);
  });
});

// ============ CART ROUTES ============

// Get cart items
app.get('/api/cart', authenticate, (req, res) => {
  db.all(
    `SELECT c.id, c.productId, c.quantity, p.name, p.price 
     FROM cart c 
     JOIN products p ON c.productId = p.id 
     WHERE c.userId = ?`,
    [req.userId],
    (err, items) => {
      if (err) {
        return res.status(500).json({ error: 'Failed to fetch cart' });
      }
      res.json(items);
    }
  );
});

// Add to cart
app.post('/api/cart', authenticate, (req, res) => {
  const { productId, quantity = 1 } = req.body;

  db.get("SELECT * FROM products WHERE id = ?", [productId], (err, product) => {
    if (err || !product) {
      return res.status(404).json({ error: 'Product not found' });
    }

    db.get(
      "SELECT * FROM cart WHERE userId = ? AND productId = ?",
      [req.userId, productId],
      (err, existingItem) => {
        if (existingItem) {
          db.run(
            "UPDATE cart SET quantity = quantity + ? WHERE id = ?",
            [quantity, existingItem.id],
            function(err) {
              if (err) {
                return res.status(500).json({ error: 'Failed to update cart' });
              }
              res.json({ message: 'Cart updated' });
            }
          );
        } else {
          db.run(
            "INSERT INTO cart (userId, productId, quantity) VALUES (?, ?, ?)",
            [req.userId, productId, quantity],
            function(err) {
              if (err) {
                return res.status(500).json({ error: 'Failed to add to cart' });
              }
              res.json({ message: 'Added to cart' });
            }
          );
        }
      }
    );
  });
});

// Update cart item quantity
app.put('/api/cart/:productId', authenticate, (req, res) => {
  const { quantity } = req.body;

  db.run(
    "UPDATE cart SET quantity = ? WHERE userId = ? AND productId = ?",
    [quantity, req.userId, req.params.productId],
    function(err) {
      if (err) {
        return res.status(500).json({ error: 'Failed to update cart' });
      }
      res.json({ message: 'Cart updated' });
    }
  );
});

// Remove from cart
app.delete('/api/cart/:productId', authenticate, (req, res) => {
  db.run(
    "DELETE FROM cart WHERE userId = ? AND productId = ?",
    [req.userId, req.params.productId],
    function(err) {
      if (err) {
        return res.status(500).json({ error: 'Failed to remove from cart' });
      }
      res.json({ message: 'Removed from cart' });
    }
  );
});

// Clear cart
app.delete('/api/cart', authenticate, (req, res) => {
  db.run("DELETE FROM cart WHERE userId = ?", [req.userId], function(err) {
    if (err) {
      return res.status(500).json({ error: 'Failed to clear cart' });
    }
    res.json({ message: 'Cart cleared' });
  });
});

// ============ ORDER ROUTES ============

// Create order
app.post('/api/orders', authenticate, (req, res) => {
  db.all("SELECT * FROM cart WHERE userId = ?", [req.userId], (err, cartItems) => {
    if (err || cartItems.length === 0) {
      return res.status(400).json({ error: 'Cart is empty' });
    }

    let total = 0;
    const orderProducts = [];

    const productIds = cartItems.map(item => item.productId);
    const placeholders = productIds.map(() => '?').join(',');

    db.all(`SELECT * FROM products WHERE id IN (${placeholders})`, productIds, (err, products) => {
      cartItems.forEach(item => {
        const product = products.find(p => p.id === item.productId);
        if (product) {
          total += product.price * item.quantity;
          orderProducts.push({ productId: item.productId, quantity: item.quantity });
        }
      });

      db.run(
        "INSERT INTO orders (userId, products, total, status) VALUES (?, ?, ?, ?)",
        [req.userId, JSON.stringify(orderProducts), total, 'pending'],
        function(err) {
          if (err) {
            return res.status(500).json({ error: 'Failed to create order' });
          }

          db.run("DELETE FROM cart WHERE userId = ?", [req.userId]);
          res.json({ 
            id: this.lastID, 
            userId: req.userId, 
            products: orderProducts, 
            total, 
            status: 'pending' 
          });
        }
      );
    });
  });
});

// Get user orders
app.get('/api/orders', authenticate, (req, res) => {
  db.all(
    "SELECT * FROM orders WHERE userId = ? ORDER BY createdAt DESC",
    [req.userId],
    (err, orders) => {
      if (err) {
        return res.status(500).json({ error: 'Failed to fetch orders' });
      }
      orders = orders.map(order => ({
        ...order,
        products: JSON.parse(order.products)
      }));
      res.json(orders);
    }
  );
});

// Get single order
app.get('/api/orders/:id', authenticate, (req, res) => {
  db.get(
    "SELECT * FROM orders WHERE id = ? AND userId = ?",
    [req.params.id, req.userId],
    (err, order) => {
      if (err || !order) {
        return res.status(404).json({ error: 'Order not found' });
      }
      order.products = JSON.parse(order.products);
      res.json(order);
    }
  );
});

app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});

