const sqlite3 = require('sqlite3').verbose();
const { open } = require('sqlite');

// 数据库连接实例
let db = null;

/**
 * 初始化数据库连接
 */
async function initializeDatabase() {
  try {
    // 打开数据库连接（如果不存在会自动创建）
    db = await open({
      filename: './database/ecommerce.db',
      driver: sqlite3.Database
    });

    console.log('Database connection established');

    // 创建数据表
    await createTables();

    // 插入初始数据（如果表为空）
    await seedInitialData();

    return db;
  } catch (error) {
    console.error('Database initialization failed:', error);
    throw error;
  }
}

/**
 * 创建所有数据表
 */
async function createTables() {
  // 用户表
  await db.run(`
    CREATE TABLE IF NOT EXISTS users (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      username TEXT UNIQUE NOT NULL,
      email TEXT UNIQUE NOT NULL,
      password TEXT NOT NULL,
      created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    )
  `);

  // 商品表
  await db.run(`
    CREATE TABLE IF NOT EXISTS products (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT NOT NULL,
      price REAL NOT NULL,
      stock INTEGER DEFAULT 0,
      category TEXT,
      description TEXT,
      created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    )
  `);

  // 购物车表（每个用户一个购物车，存储JSON格式的购物车项）
  await db.run(`
    CREATE TABLE IF NOT EXISTS carts (
      user_id INTEGER PRIMARY KEY,
      items TEXT DEFAULT '[]', -- 存储CartItem数组的JSON字符串
      updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
    )
  `);

  // 订单表
  await db.run(`
    CREATE TABLE IF NOT EXISTS orders (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL,
      products TEXT NOT NULL, -- 存储Order中products数组的JSON字符串
      total REAL NOT NULL,
      status TEXT DEFAULT 'pending',
      created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
    )
  `);

  // 创建索引以提高查询性能
  await db.run('CREATE INDEX IF NOT EXISTS idx_users_email ON users(email)');
  await db.run('CREATE INDEX IF NOT EXISTS idx_products_category ON products(category)');
  await db.run('CREATE INDEX IF NOT EXISTS idx_orders_user_id ON orders(user_id)');
  await db.run('CREATE INDEX IF NOT EXISTS idx_orders_status ON orders(status)');

  console.log('All tables created successfully');
}

/**
 * 插入初始示例数据
 */
async function seedInitialData() {
  try {
    // 检查商品表是否为空
    const productCount = await db.get('SELECT COUNT(*) as count FROM products');

    if (productCount.count === 0) {
      // 插入示例商品
      const sampleProducts = [
        { name: '智能手机', price: 2999.99, stock: 100, category: '电子产品', description: '高性能智能手机' },
        { name: '笔记本电脑', price: 6999.99, stock: 50, category: '电子产品', description: '轻薄便携笔记本电脑' },
        { name: '无线耳机', price: 499.99, stock: 200, category: '电子产品', description: '降噪无线耳机' },
        { name: '运动鞋', price: 399.99, stock: 150, category: '服装鞋帽', description: '舒适运动鞋' },
        { name: '咖啡机', price: 899.99, stock: 30, category: '家用电器', description: '全自动咖啡机' },
        { name: '书籍', price: 59.99, stock: 500, category: '图书音像', description: '畅销书籍' },
        { name: '背包', price: 199.99, stock: 80, category: '箱包配饰', description: '多功能旅行背包' },
        { name: '手表', price: 1299.99, stock: 60, category: '配饰', description: '时尚智能手表' }
      ];

      for (const product of sampleProducts) {
        await db.run(
          'INSERT INTO products (name, price, stock, category, description) VALUES (?, ?, ?, ?, ?)',
          [product.name, product.price, product.stock, product.category, product.description]
        );
      }

      console.log(`Inserted ${sampleProducts.length} sample products`);
    }

    // 检查用户表是否为空（不插入示例用户，需要用户自己注册）
    const userCount = await db.get('SELECT COUNT(*) as count FROM users');
    console.log(`Database has ${userCount.count} users`);

  } catch (error) {
    console.error('Error seeding initial data:', error);
  }
}

/**
 * 获取数据库实例
 * 如果数据库未初始化，先初始化
 */
async function getDatabase() {
  if (!db) {
    await initializeDatabase();
  }
  return db;
}

/**
 * 关闭数据库连接
 */
async function closeDatabase() {
  if (db) {
    await db.close();
    db = null;
    console.log('Database connection closed');
  }
}

/**
 * 清空所有表（仅用于测试环境）
 */
async function clearDatabase() {
  if (!db) return;

  try {
    await db.run('DELETE FROM orders');
    await db.run('DELETE FROM carts');
    await db.run('DELETE FROM products');
    await db.run('DELETE FROM users');

    // 重置自增ID
    await db.run('DELETE FROM sqlite_sequence');

    console.log('Database cleared');
  } catch (error) {
    console.error('Error clearing database:', error);
  }
}

module.exports = {
  initializeDatabase,
  getDatabase,
  closeDatabase,
  clearDatabase
};
