    const { products, total } = req.body;
    const userId = req.user.id;

    if (!products || !Array.isArray(products) || products.length === 0) {
      return res.status(400).json({ error: '购物车为空，无法创建订单' });
    }

    if (typeof total !== 'number' || total <= 0) {
      return res.status(400).json({ error: '订单总价无效' });
    }

    // 检查商品库存
    for (const item of products) {
      const product = await db.get('SELECT stock FROM products WHERE id = ?', item.productId);
      if (!product) {
        return res.status(404).json({ error: `商品ID ${item.productId} 不存在` });
      }
      if (product.stock < item.quantity) {
        return res.status(400).json({ 
          error: `商品ID ${item.productId} 库存不足，当前库存: ${product.stock}，请求数量: ${item.quantity}` 
        });
      }
    }

    // 开始事务
    await db.run('BEGIN TRANSACTION');

    try {
      // 插入订单
      const orderResult = await db.run(
        'INSERT INTO orders (userId, products, total, status, createdAt) VALUES (?, ?, ?, ?, ?)',
        [userId, JSON.stringify(products), total, 'pending', new Date().toISOString()]
      );

      // 更新商品库存
      for (const item of products) {
        await db.run(
          'UPDATE products SET stock = stock - ? WHERE id = ?',
          [item.quantity, item.productId]
        );
      }

      await db.run('COMMIT');

      const newOrder = await db.get(
        'SELECT * FROM orders WHERE id = ?',
        orderResult.lastID
      );

      // 解析JSON字符串
      newOrder.products = JSON.parse(newOrder.products);

      res.status(201).json(newOrder);
    } catch (error) {
      await db.run('ROLLBACK');
      throw error;
    }
  } catch (error) {
    console.error('创建订单失败:', error);
    res.status(500).json({ error: '创建订单失败，请稍后重试' });
  }
});

