router.get('/:id', requireAuth, async (req, res) => {
  try {
    const { id } = req.params;
    const userId = req.user.id;

    const order = await db.get(
      'SELECT * FROM orders WHERE id = ? AND userId = ?',
      [id, userId]
    );

