const db = require('../config/database');

class CartService {
  async getCart(userId) {
    return new Promise((resolve, reject) => {
      db.all(
        'SELECT * FROM cart_items WHERE userId = ?',
        [userId],
        (err, items) => {
          if (err) {
            reject(err);
          } else {
            resolve(items);
          }
        }
      );
    });
  }

  async addToCart(userId, productId, quantity) {
    return new Promise((resolve, reject) => {
      db.get(
        'SELECT * FROM cart_items WHERE userId = ? AND productId = ?',
        [userId, productId],
        (err, existingItem) => {
          if (err) {
            reject(err);
          } else if (existingItem) {
            const newQuantity = existingItem.quantity + quantity;
            db.run(
              'UPDATE cart_items SET quantity = ? WHERE userId = ? AND productId = ?',
              [newQuantity, userId, productId],
              function(updateErr) {
                if (updateErr) {
                  reject(updateErr);
                } else {
                  resolve(this.changes > 0);
                }
              }
            );
          } else {
            db.run(
              'INSERT INTO cart_items (userId, productId, quantity) VALUES (?, ?, ?)',
              [userId, productId, quantity],
              function(insertErr) {
                if (insertErr) {
                  reject(insertErr);
                } else {
                  resolve(this.lastID);
                }
              }
            );
          }
        }
      );
    });
  }

  async updateCartItem(userId, productId, quantity) {
    if (quantity <= 0) {
      return this.removeFromCart(userId, productId);
    }

    return new Promise((resolve, reject) => {
      db.run(
        'UPDATE cart_items SET quantity = ? WHERE userId = ? AND productId = ?',
        [quantity, userId, productId],
        function(err) {
          if (err) {
            reject(err);
          } else {
            resolve(this.changes > 0);
          }
        }
      );
    });
  }

  async removeFromCart(userId, productId) {
    return new Promise((resolve, reject) => {
      db.run(
        'DELETE FROM cart_items WHERE userId = ? AND productId = ?',
        [userId, productId],
        function(err) {
          if (err) {
            reject(err);
          } else {
            resolve(this.changes > 0);
          }
        }
      );
    });
  }

  async clearCart(userId) {
    return new Promise((resolve, reject) => {
      db.run(
        'DELETE FROM cart_items WHERE userId = ?',
        [userId],
        function(err) {
          if (err) {
            reject(err);
          } else {
            resolve(this.changes > 0);
          }
        }
      );
    });
  }

  async getCartWithProducts(userId) {
    return new Promise((resolve, reject) => {
      db.all(
        `SELECT ci.*, p.name, p.price, p.stock, p.category, p.description 
         FROM cart_items ci 
         JOIN products p ON ci.productId = p.id 
         WHERE ci.userId = ?`,
        [userId],
        (err, items) => {
          if (err) {
            reject(err);
          } else {
            resolve(items);
          }
        }
      );
    });
  }
}

