import React, { useState, useEffect } from 'react';
import { Product } from '../types';
import { productApi } from '../services/api';

const ProductList: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [error, setError] = useState<string>('');

  useEffect(() => {
    loadProducts();
  }, []);

  const loadProducts = async () => {
    try {
      setLoading(true);
      const data = await productApi.getAll();
      setProducts(data);
      setError('');
    } catch (err) {
      setError('Failed to load products');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = async () => {
    if (!searchTerm.trim()) {
      loadProducts();
      return;
    }
    try {
      setLoading(true);
      const data = await productApi.search(searchTerm);
      setProducts(data);
      setError('');
    } catch (err) {
      setError('Search failed');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleAddToCart = async (productId: number) => {
    try {
      const cartItem = { productId, quantity: 1 };
      await fetch('http://localhost:3001/api/cart', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(cartItem),
      });
      alert('Added to cart successfully');
    } catch (err) {
      alert('Failed to add to cart');
      console.error(err);
    }
  };

  if (loading) {
    return (
      <div style={styles.container}>
        <div style={styles.loading}>Loading products...</div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>Products</h1>

      <div style={styles.searchContainer}>
        <input
          type="text"
          placeholder="Search products..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          style={styles.searchInput}
          onKeyPress={(e) => e.key === 'Enter' && handleSearch()}
        />
        <button onClick={handleSearch} style={styles.searchButton}>
          Search
        </button>
      </div>

      {error && <div style={styles.error}>{error}</div>}

      <div style={styles.productGrid}>
        {products.map((product) => (
          <div key={product.id} style={styles.productCard}>
            <h3 style={styles.productName}>{product.name}</h3>
            <p style={styles.productCategory}>{product.category}</p>
            <p style={styles.productDescription}>{product.description}</p>
            <div style={styles.productPrice}>${product.price.toFixed(2)}</div>
            <div style={styles.productStock}>
              {product.stock > 0 ? `In Stock: ${product.stock}` : 'Out of Stock'}
            </div>
            <button
              onClick={() => handleAddToCart(product.id)}
              disabled={product.stock === 0}
              style={product.stock === 0 ? styles.disabledButton : styles.addButton}
            >
              Add to Cart
            </button>
          </div>
        ))}
      </div>

      {products.length === 0 && !loading && (
        <div style={styles.noProducts}>No products found</div>
      )}
    </div>
  );
};

