```typescript
import { useState, useEffect } from 'react';
import { cartApi, orderApi, productApi } from '../services/api';
import type { CartItem, Product } from '../types';

interface CartItemWithProduct extends CartItem {
  product?: Product;
}

export default function Cart() {
  const [cartItems, setCartItems] = useState<CartItemWithProduct[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [total, setTotal] = useState(0);

  useEffect(() => {
    loadCart();
  }, []);

  const loadCart = async () => {
    try {
      setLoading(true);
      const items = await cartApi.getCart();

      if (Array.isArray(items) && items.length > 0) {
        const itemsWithProducts = await Promise.all(
          items.map(async (item: CartItemWithProduct) => {
            try {
              const product = await productApi.getById(item.productId);
              return { ...item, product };
            } catch {
              return item;
            }
          })
        );
        setCartItems(itemsWithProducts);
        calculateTotal(itemsWithProducts);
      } else {
        setCartItems([]);
        setTotal(0);
      }
    } catch (err) {
      setError('加载购物车失败');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const calculateTotal = (items: CartItemWithProduct[]) => {
    const sum = items.reduce((acc, item) => {
      const price = item.product?.price || 0;
      return acc + price * item.quantity;
    }, 0);
    setTotal(sum);
  };

  const handleUpdateQuantity = async (productId: number, quantity: number) => {
    if (quantity < 1) return;

    try {
      await cartApi.updateItem(productId, quantity);
      const updatedItems = cartItems.map(item =>
        item.productId === productId ? { ...item, quantity } : item
      );
      setCartItems(updatedItems);
      calculateTotal(updatedItems);
    } catch (err) {
      setError('更新数量失败');
      console.error(err);
    }
  };

  const handleRemoveItem = async (productId: number) => {
    try {
      await cartApi.removeItem(productId);
      const remainingItems = cartItems.filter(item => item.productId !== productId);
      setCartItems(remainingItems);
      calculateTotal(remainingItems);
    } catch (err) {
      setError('删除商品失败');
      console.error(err);
    }
  };

  const handleClearCart = async () => {
    try {
      await cartApi.clearCart();
      setCartItems([]);
      setTotal(0);
    } catch (err) {
      setError('清空购物车失败');
      console.error(err);
    }
  };

  const handleCheckout = async () => {
    if (cartItems.length === 0) {
      setError('购物车为空');
      return;
    }

    try {
      const products = cartItems.map(item => ({
        productId: item.productId,
        quantity: item.quantity,
      }));

      await orderApi.createOrder(products, total);
      await cartApi.clearCart();

      setCartItems([]);
      setTotal(0);
      alert('订单创建成功！');
    } catch (err) {
      setError('创建订单失败');
      console.error(err);
    }
  };

  if (loading) {
    return (
      <div style={styles.container}>
        <p>加载中...</p>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>购物车</h1>

      {error && <p style={styles.error}>{error}</p>}

      {cartItems.length === 0 ? (
        <p style={styles.empty}>购物车为空</p>
      ) : (
        <>
          <div style={styles.cartList}>
            {cartItems.map(item => (
              <div key={item.productId} style={styles.cartItem}>
                <div style={styles.itemInfo}>
                  <h3 style={styles.itemName}>{item.product?.name || '商品'}</h3>
                  <p style={styles.itemPrice}>¥{item.product?.price || 0}</p>
                </div>
                <div style={styles.itemActions}>
                  <button
                    style={styles.quantityBtn}
                    onClick={() => handleUpdateQuantity(item.productId, item.quantity - 1)}
                  >
                    -
                  </button>
                  <span style={styles.quantity}>{item.quantity}</span>
                  <button
                    style={styles.quantityBtn}
                    onClick={() => handleUpdateQuantity(item.productId, item.quantity + 1)}
                  >
                    +
                  </button>
                  <button
                    style={styles.removeBtn}
                    onClick={() => handleRemoveItem(item.productId)}
                  >
                    删除
                  </button>
                </div>
              </div>
            ))}
          </div>

          <div style={styles.summary}>
            <p style={styles.total}>总计: ¥{total}</p>
            <div style={styles.actions}>
              <button style={styles.clearBtn} onClick={handleClearCart}>
                清空购物车
              </button>
              <button style={styles.checkoutBtn} onClick={handleCheckout}>
                提交订单
              </button>
            </div>
          </div>
        </>
      )}
    </div>
  );
}

const styles: { [key: string]: React.CSSProperties } = {
