                  <span style={styles.detailLabel}>Status:</span>
                  <span
                    style={{
                      ...styles.statusBadge,
                      backgroundColor: getStatusColor(selectedOrder.status),
                    }}
                  >
                    {selectedOrder.status.charAt(0).toUpperCase() +
                      selectedOrder.status.slice(1)}
                  </span>
                </div>
                <div style={styles.detailRow}>
                  <span style={styles.detailLabel}>Created:</span>
                  <span style={styles.detailValue}>
                    {formatDate(selectedOrder.createdAt)}
                  </span>
                </div>
                <div style={styles.detailRow}>
                  <span style={styles.detailLabel}>User ID:</span>
                  <span style={styles.detailValue}>{selectedOrder.userId}</span>
                </div>
              </div>

              <div style={styles.detailSection}>
                <h3 style={styles.sectionTitle}>Products</h3>
                {selectedOrder.products.map((product, idx) => (
                  <div key={idx} style={styles.productRow}>
                    <span style={styles.productInfo}>
                      Product ID: {product.productId}
                    </span>
                    <span style={styles.quantity}>× {product.quantity}</span>
