              {selectedOrder.status !== 'delivered' &&
                selectedOrder.status !== 'cancelled' && (
                  <div style={styles.statusActions}>
                    <h3 style={styles.sectionTitle}>Update Status</h3>
                    <div style={styles.statusButtons}>
                      {selectedOrder.status === 'pending' && (
                        <button
