                            handleStatusChange(selectedOrder.id, 'shipped')
                          }
                          style={styles.statusButton}
                        >
                          Ship
                        </button>
                      )}
                      {selectedOrder.status === 'shipped' && (
                        <button
                          onClick={() =>
                            handleStatusChange(selectedOrder.id, 'delivered')
                          }
                          style={styles.statusButton}
                        >
